starterCss:
/* Optimize using @scope:
   Current styles leak into nested cards.
   Use @scope to limit styles to the immediate card only,
   excluding nested .scoped-card children.
   The nested card should have its own default styling. */
.card-wrapper {
  padding: 20px;
}
/* These styles leak into nested cards */
.scoped-card {
  padding: 20px;
  border: 1px solid #dee2e6;
  border-radius: 8px;
  background-color: white;
  margin-bottom: 12px;
}
.scoped-title {
  color: #007bff;
  margin: 0 0 8px;
  font-size: 18px;
  border-bottom: 2px solid #007bff;
  padding-bottom: 8px;
}
.scoped-text {
  color: #6c757d;
  margin: 0;
  line-height: 1.5;
}

