.card-wrapper {
  padding: 20px;
}
.scoped-card {
  padding: 20px;
  border: 1px solid rgb(222, 226, 230);
  border-radius: 8px;
  background-color: rgb(255, 255, 255);
  margin-bottom: 12px;
}
@scope (.scoped-card) to (.scoped-card .scoped-card) {
  .scoped-title {
    color: rgb(0, 123, 255);
    margin: 0 0 8px;
    font-size: 18px;
    border-bottom: 2px solid rgb(0, 123, 255);
    padding-bottom: 8px;
  }
  .scoped-text {
    color: rgb(108, 117, 125);
    margin: 0;
    line-height: 1.5;
  }
}
.nested .scoped-title {
  color: rgb(73, 80, 87);
  margin: 0 0 8px;
  font-size: 16px;
  border-bottom: 1px solid rgb(222, 226, 230);
  padding-bottom: 8px;
}
.nested .scoped-text {
  color: rgb(108, 117, 125);
  margin: 0;
  line-height: 1.5;
}

